export const useProfileScreen = () => {
  const profileQuery = useProfileQuery()

  return {
    user: profileQuery.data ?? null,
    isLoading: profileQuery.isLoading,
    error: profileQuery.error,
    onRetry: profileQuery.refetch,
  }
}

